#include <bits/stdc++.h>
using namespace std;int p[1000001];
int f(int x){return p[x]==x?x:p[x]=f(p[x]);}
int main(){int n,m;scanf("%d %d",&n,&m);for(int i=0;i<=n;i++)p[i]=i;string o;while(m--){int c,a,b;scanf("%d %d %d",&c,&a,&b);if(c==0){p[f(a)]=f(b);}else{o+=(f(a)==f(b)?"YES":"NO");o+='\n';}}printf("%s",o.c_str());}
